(function(){
  var b64='';
  document.addEventListener("DOMContentLoaded",function(){
    var btn=document.getElementById("research-cert-btn");
    if(!btn)return;
    btn.addEventListener("click",function(){
      var tab=window.open("","_blank");
      if(tab){
        tab.document.write('<html><head><title>Publication Certificate</title><style>*{box-sizing:border-box;margin:0;padding:0;}body{background:#1a1a2e;min-height:100vh;display:flex;align-items:center;justify-content:center;padding:2rem;font-family:sans-serif;}.frame{background:#fff;border-radius:12px;padding:20px;box-shadow:0 8px 48px rgba(0,0,0,0.6);max-width:680px;width:100%;}.frame img{display:block;width:100%;height:auto;border-radius:4px;}</style></head><body><div class="frame"><img src="data:image/jpeg;base64,'+b64+'" alt="Publication Certificate"></div></body></html>');
        tab.document.close();
      }
    });
  });
})();
